CREATE TABLE IF NOT EXISTS users(id SERIAL PRIMARY KEY,name VARCHAR(100) NOT NULL,email VARCHAR(150) UNIQUE NOT NULL,password VARCHAR(255) NOT NULL,role VARCHAR(20) NOT NULL DEFAULT 'user' CHECK(role IN('user','seller','admin')),active BOOLEAN DEFAULT TRUE,phone VARCHAR(20),created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS categories(id SERIAL PRIMARY KEY,name VARCHAR(100) NOT NULL UNIQUE,description TEXT);
CREATE TABLE IF NOT EXISTS products(id SERIAL PRIMARY KEY,category_id INT REFERENCES categories(id) ON DELETE SET NULL,name VARCHAR(150) NOT NULL,description TEXT,price DECIMAL(10,2) NOT NULL CHECK(price>=0),weight_grams INT DEFAULT 100,image_url VARCHAR(255),stock_quantity INT DEFAULT 0,is_available BOOLEAN DEFAULT TRUE,ingredients TEXT,created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS payments(id SERIAL PRIMARY KEY,amount DECIMAL(10,2) NOT NULL,status VARCHAR(20) DEFAULT 'pending' CHECK(status IN('pending','paid','failed','refunded')),card_last4 VARCHAR(4),created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS orders(id SERIAL PRIMARY KEY,order_date TIMESTAMP DEFAULT NOW(),user_id INT REFERENCES users(id),status VARCHAR(20) DEFAULT 'новый' CHECK(status IN('новый','готовится','в доставке','доставлен','отменён')),total_price DECIMAL(10,2),delivery_address TEXT,comment TEXT,customer_name VARCHAR(100),phone VARCHAR(20),email VARCHAR(150),payment_id INT REFERENCES payments(id),estimated_delivery_at TIMESTAMP);
CREATE TABLE IF NOT EXISTS order_items(id SERIAL PRIMARY KEY,order_id INT REFERENCES orders(id) ON DELETE CASCADE,product_id INT REFERENCES products(id),quantity INT NOT NULL CHECK(quantity>0),price_per_unit DECIMAL(10,2) NOT NULL,total_item_price DECIMAL(10,2) NOT NULL);
CREATE TABLE IF NOT EXISTS reviews(id SERIAL PRIMARY KEY,product_id INT REFERENCES products(id) ON DELETE CASCADE,user_id INT REFERENCES users(id),rating INT CHECK(rating BETWEEN 1 AND 5),comment TEXT,created_at TIMESTAMP DEFAULT NOW(),is_verified_purchase BOOLEAN DEFAULT FALSE,photo_url VARCHAR(255));
CREATE INDEX IF NOT EXISTS idx_products_category ON products(category_id); CREATE INDEX IF NOT EXISTS idx_orders_user ON orders(user_id);
